"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { format, isAfter, subYears } from "date-fns";
import { motion } from "framer-motion";
import {
  Activity,
  ArrowRight,
  Calendar as CalendarIcon,
  Eye,
  EyeOff,
  Lock,
  Mail,
  Phone,
  User,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { useToast } from "@/hooks/use-toast";
import { authService } from "@/services/authService";
import { useAuthStore } from "@/store";
import { cn } from "@/lib/utils";

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const formatMobile = (raw: string) => {
  let cleaned = raw.replace(/\D/g, "");
  if (cleaned.startsWith("0")) cleaned = cleaned.slice(1);
  cleaned = cleaned.slice(0, 10);
  const part1 = cleaned.slice(0, 3);
  const part2 = cleaned.slice(3, 6);
  const part3 = cleaned.slice(6, 10);
  if (cleaned.length <= 3) return part1;
  if (cleaned.length <= 6) return `${part1}-${part2}`;
  return `${part1}-${part2}-${part3}`;
};

const normalizeMobile = (raw: string) => {
  let cleaned = raw.replace(/\D/g, "");
  if (cleaned.startsWith("0")) cleaned = cleaned.slice(1);
  return cleaned.slice(0, 10);
};

const generateOtp = () => Math.floor(100000 + Math.random() * 900000).toString();

export default function SignUpPage() {
  const router = useRouter();
  const { toast } = useToast();
  const { user, setUser } = useAuthStore();

  const [isLoading, setIsLoading] = useState(false);
  const [isSendingOtp, setIsSendingOtp] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const [firstName, setFirstName] = useState("");
  const [middleName, setMiddleName] = useState("");
  const [lastName, setLastName] = useState("");
  const [birthdate, setBirthdate] = useState<Date | undefined>();
  const [mobile, setMobile] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  const [otpToken, setOtpToken] = useState<string | null>(null);
  const [otpDigits, setOtpDigits] = useState<string[]>(Array(6).fill(""));
  const [otpSent, setOtpSent] = useState(false);
  const [otpVerified, setOtpVerified] = useState(false);
  const [resendIn, setResendIn] = useState(0);
  const otpRefs = useRef<Array<HTMLInputElement | null>>([]);

  const isEmailValid = useMemo(() => EMAIL_REGEX.test(email), [email]);
  const mobileDigits = useMemo(() => normalizeMobile(mobile), [mobile]);
  const maxAdultDate = useMemo(() => subYears(new Date(), 18), []);
  const isAdult = birthdate ? birthdate <= maxAdultDate : false;

  useEffect(() => {
    if (!user) return;
    switch (user.role) {
      case "doctor":
        router.replace("/doctor");
        break;
      case "admin":
        router.replace("/admin");
        break;
      default:
        router.replace("/patient");
    }
  }, [router, user]);

  useEffect(() => {
    if (resendIn <= 0) return;
    const timer = setInterval(() => setResendIn((prev) => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [resendIn]);

  const handleSendOtp = async () => {
    if (!isEmailValid) {
      toast({
        title: "Enter a valid email",
        description: "We will send the OTP to your email address.",
        variant: "destructive",
      });
      return;
    }

    if (resendIn > 0) return;

    setIsSendingOtp(true);
    try {
      const code = generateOtp();
      setOtpToken(code);
      setOtpSent(true);
      setOtpVerified(false);
      setOtpDigits(Array(6).fill(""));
      setResendIn(60);
      toast({
        title: "OTP sent",
        description: `Use ${code} to verify (demo).`,
      });
    } finally {
      setIsSendingOtp(false);
    }
  };

  const handleOtpChange = (index: number, value: string) => {
    const digit = value.replace(/\D/g, "").slice(0, 1);
    const next = [...otpDigits];
    next[index] = digit;
    setOtpDigits(next);

    if (digit && index < next.length - 1) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === "Backspace" && !otpDigits[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleOtpPaste = (event: React.ClipboardEvent<HTMLInputElement>) => {
    const pasted = event.clipboardData.getData("text").replace(/\D/g, "").slice(0, 6);
    if (!pasted) return;
    event.preventDefault();
    const next = Array(6).fill("");
    pasted.split("").forEach((char, idx) => {
      next[idx] = char;
    });
    setOtpDigits(next);
    const focusIndex = Math.min(pasted.length, 6) - 1;
    otpRefs.current[focusIndex]?.focus();
  };

  const handleVerifyOtp = () => {
    const otpValue = otpDigits.join("");
    if (!otpToken || otpValue.length !== 6) {
      toast({
        title: "Enter the 6-digit OTP",
        description: "Check your email and try again.",
        variant: "destructive",
      });
      return;
    }

    if (otpValue === otpToken) {
      setOtpVerified(true);
      toast({
        title: "OTP verified",
        description: "You can now set your password.",
      });
    } else {
      toast({
        title: "Invalid OTP",
        description: "Please verify the code and try again.",
        variant: "destructive",
      });
    }
  };

  const validateForm = () => {
    if (!firstName.trim()) return "First name is required.";
    if (!lastName.trim()) return "Last name is required.";
    if (!birthdate) return "Birthdate is required.";
    if (!isAdult) return "You must be at least 18 years old.";
    if (!mobileDigits || mobileDigits.length !== 10 || !mobileDigits.startsWith("9")) {
      return "Enter a valid Philippine mobile number.";
    }
    if (!email.trim() || !isEmailValid) return "Enter a valid email address.";
    if (!otpVerified) return "Please verify your OTP.";
    if (!password) return "Password is required.";
    if (password !== confirmPassword) return "Passwords do not match.";
    return null;
  };

  const handleRegister = async (event: React.FormEvent) => {
    event.preventDefault();

    const error = validateForm();
    if (error) {
      toast({ title: "Check your details", description: error, variant: "destructive" });
      return;
    }

    setIsLoading(true);
    try {
      const response = await authService.register({
        email,
        password,
        firstName,
        middleName,
        lastName,
        birthdate: birthdate?.toISOString(),
        phone: `+63${mobileDigits}`,
        role: "patient",
        otp: otpDigits.join(""),
      });

      if (response.success && response.data) {
        setUser(response.data);
        toast({
          title: "Account created!",
          description: "Welcome to CareConnect.",
        });
        router.push("/patient");
      } else {
        toast({
          title: "Registration failed",
          description: response.error || "Please try again.",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Error",
        description: "Something went wrong. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const canSubmit =
    otpVerified && password.length > 0 && password === confirmPassword && !isLoading;

  return (
    <div className="min-h-screen bg-background flex">
      <div className="hidden lg:flex lg:w-1/2 gradient-hero p-12 items-center justify-center relative overflow-hidden">
        <div className="absolute inset-0 bg-grid-white/10" />
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="relative text-center max-w-md"
        >
          <div className="flex items-center justify-center gap-3 mb-8">
            <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-white/20 backdrop-blur">
              <Activity className="h-8 w-8 text-white" />
            </div>
            <span className="text-3xl font-bold text-white">CareConnect</span>
          </div>

          <h1 className="text-4xl font-bold text-white mb-4">Healthcare made simple</h1>
          <p className="text-lg text-white/80">
            Book appointments, connect with trusted doctors, and manage your health profile in minutes.
          </p>

          <div className="mt-12 grid grid-cols-1 sm:grid-cols-3 gap-6 max-w-3xl mx-auto">
            <div className="text-center space-y-2">
              <div className="text-3xl font-bold text-white">Book</div>
              <p className="text-sm text-white/80">
                Easily connect with your doctors
              </p>
            </div>

            <div className="text-center space-y-2">
              <div className="text-3xl font-bold text-white">Consult</div>
              <p className="text-sm text-white/80">
                Visit your doctor or consult online
              </p>
            </div>

            <div className="text-center space-y-2">
              <div className="text-3xl font-bold text-white">Order</div>
              <p className="text-sm text-white/80">
                Your medicine delivered to you
              </p>
            </div>
          </div>
        </motion.div>
      </div>

      <div className="flex-1 flex items-center justify-center p-6 sm:p-12">
        <motion.div
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.6 }}
          className="w-full max-w-md"
        >
          <div className="flex items-center justify-center gap-2 mb-8 lg:hidden">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg gradient-primary">
              <Activity className="h-6 w-6 text-primary-foreground" />
            </div>
            <span className="text-2xl font-bold text-foreground">CareConnect</span>
          </div>

          <Card className="border-border shadow-lg">
            <CardHeader className="space-y-1">
              <CardTitle className="text-2xl">Create your CareConnect account</CardTitle>
              <CardDescription>Healthcare made simple</CardDescription>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleRegister} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="first-name">First Name</Label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      id="first-name"
                      placeholder="Juan"
                      value={firstName}
                      onChange={(event) => setFirstName(event.target.value)}
                      className="pl-10"
                      required
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="middle-name">Middle Name (optional)</Label>
                  <Input
                    id="middle-name"
                    placeholder="D."
                    value={middleName}
                    onChange={(event) => setMiddleName(event.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="last-name">Last Name</Label>
                  <Input
                    id="last-name"
                    placeholder="Dela Cruz"
                    value={lastName}
                    onChange={(event) => setLastName(event.target.value)}
                    required
                  />
                </div>

                {/* Birthdate - FIXED CALENDAR */}
                <div className="space-y-2">
                  <Label>Birthdate</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        variant="outline"
                        className={cn(
                          "w-full justify-start text-left font-normal",
                          !birthdate && "text-muted-foreground"
                        )}
                      >
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {birthdate ? format(birthdate, "PPP") : "Select your birthdate"}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0" align="start">
                      <Calendar
                        mode="single"
                        selected={birthdate}
                        onSelect={setBirthdate}
                        disabled={(date) => isAfter(date, maxAdultDate)} // Disable future dates & under 18
                        initialFocus
                        captionLayout="dropdown"
                        fromYear={1900}
                        toYear={maxAdultDate.getFullYear()}
                      />
                    </PopoverContent>
                  </Popover>
                  <p className="text-xs text-muted-foreground">
                    You must be at least 18 years old to register.
                  </p>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="mobile">Mobile Number</Label>
                  <div className="flex items-center gap-2">
                    <div className="flex items-center rounded-md border bg-background px-3 text-sm text-muted-foreground">
                      +63
                    </div>
                    <div className="relative flex-1">
                      <Phone className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                      <Input
                        id="mobile"
                        type="tel"
                        inputMode="numeric"
                        placeholder="9XX-XXX-XXXX"
                        value={formatMobile(mobile)}
                        onChange={(event) => setMobile(event.target.value)}
                        className="pl-10"
                        required
                      />
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="signup-email">Email</Label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      id="signup-email"
                      type="email"
                      placeholder="you@example.com"
                      value={email}
                      onChange={(event) => {
                        setEmail(event.target.value);
                        setOtpVerified(false);
                        setOtpSent(false);
                        setOtpToken(null);
                        setOtpDigits(Array(6).fill(""));
                        setResendIn(0);
                      }}
                      className="pl-10"
                      required
                    />
                  </div>
                </div>

                {email.length > 0 && (
                  <div className="space-y-3 rounded-md border bg-muted/30 p-3">
                    <div className="flex items-center justify-between gap-3">
                      <div>
                        <p className="text-sm font-medium text-foreground">Email OTP</p>
                        <p className="text-xs text-muted-foreground">
                          Enter the 6-digit code sent to your email.
                        </p>
                      </div>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={handleSendOtp}
                        disabled={isSendingOtp || !isEmailValid || resendIn > 0}
                      >
                        {otpSent ? "Resend OTP" : "Send OTP"}
                      </Button>
                    </div>

                    <div className="flex flex-col gap-3">
                      <div className="flex items-center justify-center gap-2">
                        {otpDigits.map((digit, index) => (
                          <Input
                            key={index}
                            ref={(el) => {
                              otpRefs.current[index] = el;
                            }}
                            value={digit}
                            onChange={(event) => handleOtpChange(index, event.target.value)}
                            onKeyDown={(event) => handleOtpKeyDown(index, event)}
                            onPaste={index === 0 ? handleOtpPaste : undefined}
                            inputMode="numeric"
                            maxLength={1}
                            disabled={!otpSent}
                            className="h-11 w-11 text-center text-lg"
                          />
                        ))}
                      </div>
                      <div className="flex items-center justify-between">
                        <p className={cn("text-xs", otpVerified ? "text-primary" : "text-muted-foreground")}>
                          {otpVerified
                            ? "OTP verified"
                            : resendIn > 0
                              ? `Resend available in ${resendIn}s`
                              : "Waiting for verification"}
                        </p>
                        <Button
                          type="button"
                          variant="secondary"
                          size="sm"
                          onClick={handleVerifyOtp}
                          disabled={!otpSent || otpVerified}
                        >
                          Verify OTP
                        </Button>
                      </div>
                    </div>
                  </div>
                )}

                {otpVerified && (
                  <>
                    <div className="space-y-2">
                      <Label htmlFor="signup-password">Password</Label>
                      <div className="relative">
                        <Lock className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                        <Input
                          id="signup-password"
                          type={showPassword ? "text" : "password"}
                          placeholder="Create a password"
                          value={password}
                          onChange={(event) => setPassword(event.target.value)}
                          className="pl-10 pr-10"
                          required
                        />
                        <button
                          type="button"
                          onClick={() => setShowPassword((prev) => !prev)}
                          className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                          aria-label={showPassword ? "Hide password" : "Show password"}
                        >
                          {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                        </button>
                      </div>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="confirm-password">Confirm Password</Label>
                      <div className="relative">
                        <Lock className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                        <Input
                          id="confirm-password"
                          type={showConfirmPassword ? "text" : "password"}
                          placeholder="Confirm your password"
                          value={confirmPassword}
                          onChange={(event) => setConfirmPassword(event.target.value)}
                          className="pl-10 pr-10"
                          required
                        />
                        <button
                          type="button"
                          onClick={() => setShowConfirmPassword((prev) => !prev)}
                          className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                          aria-label={showConfirmPassword ? "Hide password" : "Show password"}
                        >
                          {showConfirmPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                        </button>
                      </div>
                    </div>
                  </>
                )}

                <Button type="submit" className="w-full gradient-primary border-0" disabled={!canSubmit}>
                  {isLoading ? "Creating account..." : "Create Account"}
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Button>
              </form>

              <div className="mt-6 text-center text-sm text-muted-foreground">
                Already have an account?{" "}
                <Link href="/signin" className="text-primary hover:underline">
                  Sign In
                </Link>
              </div>

              <p className="mt-4 text-center text-xs text-muted-foreground">
                By creating an account you agree to our Terms &amp; Privacy Policy.
              </p>
            </CardContent>
          </Card>
        </motion.div>
      </div>
    </div>
  );
}
